// Extract bill details from email
const email = $input.first().json;

const subject = email.subject || '';
const snippet = email.snippet || '';
const from = email.from || '';
const date = email.date || new Date().toISOString();

// Extract amount (look for ₹ or Rs patterns)
const amountMatch = snippet.match(/[₹R][sS]?[\s.]?([\d,]+\.?\d*)/);
const amount = amountMatch ? amountMatch[1].replace(/,/g, '') : '0';

// Extract due date
const dueDateMatch = snippet.match(/due\s+date[\s:]*(\d{1,2}[\-\/\s]*(?:Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)[a-z]*[\-\/\s]*\d{2,4})/i);
const dueDate = dueDateMatch ? dueDateMatch[1] : '';

// Extract biller name
const biller = from.replace(/<.*>/, '').trim();

return [{
  json: {
    date,
    biller,
    subject,
    amount: parseFloat(amount),
    dueDate,
    emailId: email.id,
    status: 'Pending'
  }
}];
